# board.py

class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize pieces on the board
        piece_types = ['r', 'b']  # r for red, b for black
        initial_positions = [(0, 1), (0, 3), (0, 5), (0, 7),
                             (1, 0), (1, 2), (1, 4), (1, 6),
                             (2, 1), (2, 3), (2, 5), (2, 7)]

        for i in range(3):
            for col in initial_positions:
                row = col[0] + 1 if i == 0 else 7 - col[0]
                self.board[row][col[1]] = Piece(piece_types[i])

        # Initialize remaining squares as empty
        for i in range(8):
            for j in range(8):
                if self.board[i][j] is None:
                    self.board[i][j] = EmptySquare()

    def print_board(self):
        board_str = "  a b c d e f g h\n"
        for row in range(8):
            board_str += f"{row + 1} |"
            for col in range(8):
                if isinstance(self.board[row][col], Piece):
                    board_str += self.board[row][col].symbol
                else:
                    board_str += ". "
            board_str += "|\n"
        print(board_str)

    def get_piece(self, row, col):
        return self.board[row][col]

    def set_piece(self, row, col, piece):
        self.board[row][col] = piece

    def move_piece(self, start_row, start_col, end_row, end_col):
        piece = self.get_piece(start_row, start_col)
        if piece is not None:
            new_position = self.get_piece(end_row, end_col)
            if new_position is None or isinstance(new_position, EmptySquare):
                self.set_piece(end_row, end_col, piece)
                self.set_piece(start_row, start_col, EmptySquare())
                return True
        return False

class Piece:
    def __init__(self, color):
        self.color = color
        if color == 'r':
            self.symbol = 'R'
        else:
            self.symbol = 'B'

class EmptySquare:
    def __init__(self):
        self.symbol = '.'
```

